async function cargarSolicitudes() {
  const { data: solicitudes, error } = await supabase
    .from("solicitudes_v2")
    .select("*")
    .order("created_at", { ascending: false });

  if (error || !solicitudes) return;

  const { data: perfiles } = await supabase.from("perfiles").select("*");

  document.getElementById("total-usuarios").textContent = perfiles?.length || 0;
  document.getElementById("total-solicitudes").textContent = solicitudes.length;
  document.getElementById("total-pendientes").textContent = solicitudes.filter(s => s.estado === "pendiente").length;
  document.getElementById("total-completadas").textContent = solicitudes.filter(s => s.estado === "completado").length;

  // Solo mostrar pendientes y en proceso
  const activas = solicitudes.filter(s => s.estado !== "completado");

  const tbody = document.getElementById("tabla-solicitudes");
  tbody.innerHTML = "";

  if (activas.length === 0) {
    tbody.innerHTML = `<tr><td colspan="9" class="sin-datos">No hay solicitudes activas</td></tr>`;
    return;
  }

  renderFilas(activas, tbody);
}

function renderFilas(solicitudes, tbody) {
  tbody.innerHTML = "";
  for (const s of solicitudes) {
    const fecha = new Date(s.created_at).toLocaleDateString("es-EC");
    const tipo = s.tipo_solicitud === "multiple" ? "👥 Múltiple" : "👤 Personal";
    const personas = s.tipo_solicitud === "multiple"
      ? 1 + (JSON.parse(s.personas_adicionales || "[]").length)
      : 1;

    let badgeClass = "badge-pendiente";
    if (s.estado === "en proceso") badgeClass = "badge-proceso";
    if (s.estado === "completado") badgeClass = "badge-completado";

    let archivosHtml = "-";
    if (s.archivos) {
      try {
        const arr = JSON.parse(s.archivos);
        if (arr.length > 0) {
          archivosHtml = arr.map(a => `<a href="${a.link}" target="_blank" style="color:#0e3d92;font-size:0.75rem;display:block;">📎 ${a.nombre}</a>`).join("");
        }
      } catch(e) {}
    }

    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>${fecha}</td>
      <td>${s.nombre_completo || "-"}</td>
      <td>${s.correo || "-"}</td>
      <td>${s.tipo_servicio || "-"}</td>
      <td>${s.periodo_fiscal || "-"}</td>
      <td>${tipo} (${personas})</td>
      <td>${archivosHtml}</td>
      <td><span class="badge ${badgeClass}">${s.estado}</span></td>
      <td>
        <div class="acciones-cell">
          <button class="btn-pdf" onclick="descargarPDF('${s.id}')">📄 PDF</button>
          <button class="btn-estado" onclick="cambiarEstado('${s.id}', '${s.estado}')">✏️ Estado</button>
          <button class="btn-estado" onclick="abrirMensaje('${s.user_id}', '${s.correo}')">✉️ Mensaje</button>
        </div>
      </td>
    `;
    tbody.appendChild(tr);
  }
}

window.cambiarEstado = async (id, estadoActual) => {
  const estados = ["pendiente", "en proceso", "completado"];
  const siguiente = estados[(estados.indexOf(estadoActual) + 1) % estados.length];
  await supabase.from("solicitudes_v2").update({ estado: siguiente }).eq("id", id);
  cargarSolicitudes();
};

// Modal historial
window.abrirHistorial = async function() {
  const { data: solicitudes } = await supabase
    .from("solicitudes_v2")
    .select("*")
    .order("created_at", { ascending: false });

  const tbody = document.getElementById("tabla-historial");
  tbody.innerHTML = "";

  if (!solicitudes || solicitudes.length === 0) {
    tbody.innerHTML = `<tr><td colspan="9" class="sin-datos">No hay solicitudes</td></tr>`;
  } else {
    for (const s of solicitudes) {
      const fecha = new Date(s.created_at).toLocaleDateString("es-EC");
      const tipo = s.tipo_solicitud === "multiple" ? "👥 Múltiple" : "👤 Personal";

      let badgeClass = "badge-pendiente";
      if (s.estado === "en proceso") badgeClass = "badge-proceso";
      if (s.estado === "completado") badgeClass = "badge-completado";

      let archivosHtml = "-";
      if (s.archivos) {
        try {
          const arr = JSON.parse(s.archivos);
          if (arr.length > 0) {
            archivosHtml = arr.map(a => `<a href="${a.link}" target="_blank" style="color:#0e3d92;font-size:0.75rem;display:block;">📎 ${a.nombre}</a>`).join("");
          }
        } catch(e) {}
      }

      const tr = document.createElement("tr");
      tr.innerHTML = `
        <td>${fecha}</td>
        <td>${s.nombre_completo || "-"}</td>
        <td>${s.correo || "-"}</td>
        <td>${s.tipo_servicio || "-"}</td>
        <td>${s.periodo_fiscal || "-"}</td>
        <td>${tipo}</td>
        <td>${archivosHtml}</td>
        <td><span class="badge ${badgeClass}">${s.estado}</span></td>
        <td><button class="btn-pdf" onclick="descargarPDF('${s.id}')">📄 PDF</button></td>
      `;
      tbody.appendChild(tr);
    }
  }

  document.getElementById("modal-historial").style.display = "flex";
};

window.cerrarHistorial = function() {
  document.getElementById("modal-historial").style.display = "none";
};

window.descargarPDF = async (id) => {
  const { jsPDF } = window.jspdf;
  const { data: s } = await supabase.from("solicitudes_v2").select("*").eq("id", id).single();

  const doc = new jsPDF();
  const margen = 20;
  let y = 15;

  const LOGO = "data:image/png;base64,";
  doc.addImage(LOGO, "PNG", margen, y, 20, 20);
  doc.setTextColor(14, 61, 146);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text("Guijarro & Guijarro", margen + 25, y + 8);
  doc.setFontSize(12);
  doc.text("Asesores Tributarios", margen + 25, y + 16);
  y += 30;

  doc.setDrawColor(14, 61, 146);
  doc.setLineWidth(0.8);
  doc.line(margen, y, 210 - margen, y);
  y += 8;

  doc.setTextColor(30, 30, 30);
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  const fechaDoc = new Date(s.created_at).toLocaleDateString("es-EC", { day: "numeric", month: "long", year: "numeric" });
  doc.text("Solicitud de Proceso", margen, y);
  doc.text(fechaDoc, 210 - margen, y, { align: "right" });
  y += 10;

  doc.setFillColor(248, 183, 0);
  doc.rect(margen, y, 170, 10, "F");
  doc.setTextColor(14, 61, 146);
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.text("  Datos del Cliente", margen + 2, y + 7);
  y += 16;

  doc.setTextColor(30, 30, 30);
  doc.setFontSize(10);
  const datosCliente = [
    ["Tipo Contribuyente:", s.tipo_contribuyente || "-"],
    ["Nombre / Razón Social:", s.nombre_completo || "-"],
    ["Cédula / RUC:", s.cedula_ruc || "-"],
    ["Teléfono:", s.telefono || "-"],
    ["Dirección:", s.direccion || "-"],
    ["Ciudad:", s.ciudad || "-"],
    ["Correo:", s.correo || "-"],
    ["Actividad Económica:", s.actividad_economica || "-"],
  ];
  for (const [label, valor] of datosCliente) {
    doc.setFont("helvetica", "bold");
    doc.text(label, margen + 2, y);
    doc.setFont("helvetica", "normal");
    const lineas = doc.splitTextToSize(valor, 100);
    doc.text(lineas, margen + 60, y);
    y += lineas.length > 1 ? lineas.length * 6 : 7;
  }
  y += 4;

  doc.setFillColor(248, 183, 0);
  doc.rect(margen, y, 170, 10, "F");
  doc.setTextColor(14, 61, 146);
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.text("  Detalles del Proceso", margen + 2, y + 7);
  y += 16;

  doc.setTextColor(30, 30, 30);
  doc.setFontSize(10);
  const detalles = [
    ["Tipo de Servicio:", s.tipo_servicio || "-"],
    ["Período Fiscal:", s.periodo_fiscal || "-"],
    ["Fecha Límite:", s.fecha_limite || "-"],
    ["Estado:", s.estado || "-"],
  ];
  for (const [label, valor] of detalles) {
    doc.setFont("helvetica", "bold");
    doc.text(label, margen + 2, y);
    doc.setFont("helvetica", "normal");
    doc.text(valor, margen + 55, y);
    y += 7;
  }

  if (s.descripcion) {
    y += 4;
    doc.setFont("helvetica", "bold");
    doc.text("Descripción:", margen + 2, y);
    y += 7;
    doc.setFont("helvetica", "normal");
    const lineas = doc.splitTextToSize(s.descripcion, 165);
    doc.text(lineas, margen + 2, y);
    y += lineas.length * 6;
  }

  if (s.personas_adicionales) {
    try {
      const personas = JSON.parse(s.personas_adicionales);
      if (personas.length > 0) {
        y += 4;
        doc.setFillColor(248, 183, 0);
        doc.rect(margen, y, 170, 10, "F");
        doc.setTextColor(14, 61, 146);
        doc.setFontSize(11);
        doc.setFont("helvetica", "bold");
        doc.text("  Personas Adicionales", margen + 2, y + 7);
        y += 16;
        doc.setTextColor(30, 30, 30);
        doc.setFontSize(10);
        for (let i = 0; i < personas.length; i++) {
          const p = personas[i];
          if (y > 255) { doc.addPage(); y = 20; }
          doc.setFont("helvetica", "bold");
          doc.text(`Persona ${i + 2}:`, margen + 2, y); y += 7;
          doc.setFont("helvetica", "normal");
          doc.text(`Nombre: ${p.nombre || "-"}`, margen + 8, y); y += 6;
          doc.text(`Cédula/RUC: ${p.cedula || "-"}`, margen + 8, y); y += 6;
          doc.text(`Servicio: ${p.servicio || "-"}`, margen + 8, y); y += 6;
          doc.text(`Período: ${p.periodo || "-"}`, margen + 8, y); y += 10;
        }
      }
    } catch(e) {}
  }

  doc.setFillColor(14, 61, 146);
  doc.rect(0, 285, 210, 15, "F");
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("Guijarro & Guijarro Asesores Tributarios  |  gygasesores1@gmail.com", margen, 293);

  doc.save(`solicitud_${s.id.substring(0, 8)}.pdf`);
};

window.abrirMensaje = function(userId, correo) {
  document.getElementById("modal-user-id").value = userId;
  document.getElementById("modal-para").value = correo;
  document.getElementById("modal-asunto").value = "";
  document.getElementById("modal-mensaje-texto").value = "";
  document.getElementById("modal-resultado").textContent = "";
  document.getElementById("modal-mensaje").style.display = "flex";
};

window.cerrarModal = function() {
  document.getElementById("modal-mensaje").style.display = "none";
};

window.enviarMensaje = async () => {
  const userId = document.getElementById("modal-user-id").value;
  const asunto = document.getElementById("modal-asunto").value;
  const mensaje = document.getElementById("modal-mensaje-texto").value;

  if (!asunto.trim() || !mensaje.trim()) {
    document.getElementById("modal-resultado").style.color = "red";
    document.getElementById("modal-resultado").textContent = "Por favor completa todos los campos.";
    return;
  }

  const { error } = await supabase.from("mensajes").insert({
    user_id: userId,
    destinatario_id: userId,
    remitente: "G & G Asesores Tributarios",
    asunto: asunto,
    mensaje: mensaje,
    leido: false
  });

  if (error) {
    document.getElementById("modal-resultado").style.color = "red";
    document.getElementById("modal-resultado").textContent = "Error al enviar: " + error.message;
  } else {
    document.getElementById("modal-resultado").style.color = "green";
    document.getElementById("modal-resultado").textContent = "✅ Mensaje enviado correctamente.";
    setTimeout(() => cerrarModal(), 1500);
  }
};

async function cargarRespuestas() {
  const { data: respuestas, error } = await supabase
    .from("mensajes")
    .select("*")
    .eq("es_respuesta", true)
    .order("created_at", { ascending: false });

  const { data: perfiles } = await supabase.from("perfiles").select("*");
  const tbody = document.getElementById("tabla-respuestas");

  if (error || !respuestas || respuestas.length === 0) {
    tbody.innerHTML = `<tr><td colspan="6" class="sin-datos">No hay respuestas aún</td></tr>`;
    return;
  }

  tbody.innerHTML = "";
  for (const r of respuestas) {
    const fecha = new Date(r.created_at).toLocaleDateString("es-EC");
    const perfil = perfiles?.find(p => p.user_id === r.user_id);
    const nombre = perfil ? `${perfil.nombres || ""} ${perfil.apellidos || ""}`.trim() : "-";
    const ruc = perfil?.ruc || "-";
    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>${fecha}</td>
      <td>${nombre}</td>
      <td>${ruc}</td>
      <td>${r.remitente}</td>
      <td>${r.asunto || "-"}</td>
      <td>${r.mensaje}</td>
    `;
    tbody.appendChild(tr);
  }
}

